const input = $input.first().json;
const body = input.body || input;

const sessionId = body.session_id;
if (!sessionId) throw new Error('session_id is required');

return [{ json: {
  session_id: sessionId,
  idea_id: body.idea_id,
  voice_script_id: body.voice_script_id,
  video_prompt_id: body.video_prompt_id,
  product_image_url: body.product_image_url || '',
  artikul: body.artikul || '',
  show_artikul: body.show_artikul || false,
  heygen_avatar_id: body.heygen_avatar_id || '',
  heygen_voice_id: body.heygen_voice_id || '',
  heygen_background: body.heygen_background || '',
  heygen_ratio: body.heygen_ratio || '9:16',
  subtitles_enabled: body.subtitles_enabled != null ? !!body.subtitles_enabled : null,
  music_file_key: body.music_file_key || '',
  music_volume: parseFloat(body.music_volume) || 0.3
}}];

const dbData = $input.first().json;
const params = $('🔍 Валидация входа').first().json;

const heygenAvatarId = params.heygen_avatar_id || dbData.default_heygen_avatar_id || '';
const heygenVoiceId = params.heygen_voice_id || dbData.default_heygen_voice_id || '';
const falApiKey = dbData.fal_api_key || '';
const productImageUrl = params.product_image_url || '';

if (!heygenAvatarId) throw new Error('HeyGen avatar_id not set for product+avatar pipeline');
if (!heygenVoiceId) throw new Error('HeyGen voice_id not set for product+avatar pipeline');
if (!productImageUrl) throw new Error('product_image_url is required for product+avatar pipeline');
if (!falApiKey) throw new Error('fal_api_key not set in app_settings — configure FAL.ai API key in Settings');

const captionsEnabled = params.subtitles_enabled != null
  ? !!params.subtitles_enabled
  : (dbData.db_subtitles_enabled != null ? !!dbData.db_subtitles_enabled : false);

const musicFileKey = params.music_file_key || dbData.db_music_file_key || '';
const musicVolume = params.music_volume != null
  ? parseFloat(params.music_volume)
  : (parseFloat(dbData.db_music_volume) || 0.3);

let montageScript = dbData.montage_script || [];
if (typeof montageScript === 'string') {
  try { montageScript = JSON.parse(montageScript); } catch(e) { montageScript = []; }
}
if (!montageScript.length) {
  montageScript = [
    { order: 1, source: 'product', duration: 7, purpose: 'Хук — показываем продукт' },
    { order: 2, source: 'heygen', duration: 25, purpose: 'Аватар говорит' },
    { order: 3, source: 'product', duration: 8, purpose: 'CTA — финальный показ' }
  ];
}

return [{ json: {
  ...params,
  heygen_avatar_id: heygenAvatarId,
  heygen_voice_id: heygenVoiceId,
  heygen_background: params.heygen_background || dbData.default_heygen_bg || '#f5f5f5',
  heygen_ratio: params.heygen_ratio || '9:16',
  fal_api_key: falApiKey,
  product_image_url: productImageUrl,
  product_video_prompt: dbData.product_video_prompt || 'Product showcase video, smooth cinematic motion, photorealistic, vertical format 9:16',
  captions_enabled: captionsEnabled,
  music_file_key: musicFileKey,
  music_volume: musicVolume,
  montage_script: montageScript,
  script_text: dbData.script_text || '',
  timing_marks: dbData.timing_marks || [],
  title: dbData.title || '',
  concept: dbData.concept || '',
  visual_description: dbData.visual_description || ''
}}];

