const ctx = $('🔗 Объединение данных').first().json;

const heygenBody = {
  video_inputs: [
    {
      character: {
        type: 'avatar',
        avatar_id: ctx.heygen_avatar_id,
        avatar_style: 'normal'
      },
      voice: {
        type: 'text',
        input_text: ctx.script_text,
        voice_id: ctx.heygen_voice_id,
        speed: 1.0
      },
      background: {
        type: 'color',
        value: ctx.heygen_background || '#f5f5f5'
      }
    }
  ],
  dimension: { width: 1080, height: 1920 },
  aspect_ratio: '9:16',
  test: false
};

return [{ json: {
  session_id: ctx.session_id,
  fal_api_key: ctx.fal_api_key,
  product_image_url: ctx.product_image_url,
  product_video_prompt: ctx.product_video_prompt,
  montage_script: ctx.montage_script,
  music_file_key: ctx.music_file_key,
  music_volume: ctx.music_volume,
  body: JSON.stringify(heygenBody)
}}];

const response = $input.first().json;
const data = response.data || response;
const videoId = data.video_id;
if (!videoId) throw new Error('HeyGen did not return video_id: ' + JSON.stringify(response).substring(0, 500));

return [{ json: {
  heygen_video_id: videoId,
  session_id: $('🏗️ HeyGen запрос').first().json.session_id,
  poll_count: 0
}}];

const prev = $input.first().json;
const status = (prev.data?.status || prev.status || 'unknown').toLowerCase();
if (status === 'failed') throw new Error('HeyGen video generation failed: ' + JSON.stringify(prev.data?.error || prev).substring(0, 300));

const pollCount = (prev.poll_count || 0) + 1;
if (pollCount > 60) throw new Error('HeyGen timeout: 60 polls (20 min)');

return [{ json: {
  heygen_video_id: prev.data?.video_id || prev.data?.id || $('🔑 HeyGen video_id').first().json.heygen_video_id,
  session_id: $('🔑 HeyGen video_id').first().json.session_id,
  poll_count: pollCount
}}];

const response = $input.first().json;
const data = response.data || response;
const videoUrl = data.video_url;
if (!videoUrl) throw new Error('HeyGen did not return video_url: ' + JSON.stringify(data).substring(0, 300));

return [{ json: {
  heygen_video_url: videoUrl,
  session_id: $('🔑 HeyGen video_id').first().json.session_id
}}];

