const ctx = $('🔗 Объединение данных').first().json;
return [{ json: {
  session_id: ctx.session_id,
  fal_api_key: ctx.fal_api_key,
  product_image_url: ctx.product_image_url,
  product_video_prompt: ctx.product_video_prompt || 'Product showcase, smooth cinematic motion, high quality, photorealistic'
}}];

const response = $input.first().json;
const ctx = $('🔗 Объединение данных').first().json;

if (!response.request_id) {
  throw new Error('FAL did not return request_id: ' + JSON.stringify(response).substring(0, 300));
}

return [{ json: {
  fal_request_id: response.request_id,
  fal_api_key: ctx.fal_api_key,
  session_id: ctx.session_id,
  poll_count: 0
}}];

const prev = $input.first().json;
const status = (prev.status || '').toUpperCase();
if (status === 'FAILED' || status === 'ERROR') {
  throw new Error('FAL product video failed: ' + JSON.stringify(prev).substring(0, 300));
}

const pollCount = (prev.poll_count || 0) + 1;
if (pollCount > 60) throw new Error('FAL WAN timeout after ' + pollCount + ' polls');

return [{ json: {
  fal_request_id: $('🔑 FAL request_id').first().json.fal_request_id,
  fal_api_key: $('🔑 FAL request_id').first().json.fal_api_key,
  session_id: $('🔑 FAL request_id').first().json.session_id,
  poll_count: pollCount
}}];

const response = $input.first().json;
const videoUrl = response.output?.video?.url;
if (!videoUrl) {
  throw new Error('FAL did not return video URL: status=' + response.status + ' output=' + JSON.stringify(response.output || {}).substring(0, 200));
}

return [{ json: {
  product_video_url: videoUrl,
  session_id: $('🔑 FAL request_id').first().json.session_id
}}];

const ctx = $('🔗 Объединение данных').first().json;
const heygenVideoUrl = $('🎬 HeyGen URL').first().json.heygen_video_url;
const productVideoUrl = $('🎬 FAL продукт URL').first().json.product_video_url;

const sessionId = ctx.session_id;
const montageScript = ctx.montage_script || [
  { order: 1, source: 'product', duration: 7, purpose: 'Хук' },
  { order: 2, source: 'heygen', duration: 25, purpose: 'Аватар говорит' },
  { order: 3, source: 'product', duration: 8, purpose: 'CTA' }
];
const musicFileKey = ctx.music_file_key || '';
const musicVolume = parseFloat(ctx.music_volume) || 0.3;

const segments = [...montageScript].sort((a, b) => a.order - b.order);
const totalDuration = segments.reduce((s, seg) => s + (seg.duration || 5), 0);

// Build FFmpeg filter_complex:
// input 0: heygen.mp4  — avatar (video + audio = HeyGen voice, always primary audio)
// input 1: product.mp4 — product video (video only, looped via -stream_loop -1)
// input 2 (optional): music.mp3
let heygenCursor = 0;   // position in HeyGen video (for heygen video segments)
let productCursor = 0;  // position in product video (looped, per-product-segment total)
const filterParts = [];
const segLabels = [];
const scale = 'scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2,setsar=1';

segments.forEach((seg, i) => {
  const dur = seg.duration || 5;
  if (seg.source === 'heygen') {
    filterParts.push(`[0:v]trim=${heygenCursor}:${heygenCursor + dur},setpts=PTS-STARTPTS,${scale}[sv${i}]`);
    heygenCursor += dur;
  } else {
    // product: looped input 1
    filterParts.push(`[1:v]trim=${productCursor}:${productCursor + dur},setpts=PTS-STARTPTS,${scale}[sv${i}]`);
    productCursor += dur;
  }
  segLabels.push(`[sv${i}]`);
});

filterParts.push(`${segLabels.join('')}concat=n=${segments.length}:v=1:a=0[vout]`);
// HeyGen audio is always the primary track (avatar speaks throughout the whole video)
filterParts.push(`[0:a]atrim=0:${totalDuration},asetpts=PTS-STARTPTS,apad=whole_dur=${totalDuration}[atrm]`);

let audioFinal = '[atrm]';
let musicInput = '';

if (musicFileKey) {
  const safeKey = musicFileKey.replace(/'/g, "'\\''");
  musicInput = ` -i /home/node/music/${safeKey}`;
  filterParts.push(`[atrm][2:a]amix=inputs=2:duration=first:weights=1 ${musicVolume.toFixed(2)}[aout]`);
  audioFinal = '[aout]';
}

const filterComplex = filterParts.join(';');

const heygenPath = `/home/node/output/hg_${sessionId}.mp4`;
const productPath = `/home/node/output/prod_${sessionId}.mp4`;
const outputPath = `/home/node/output/dual_final_${sessionId}.mp4`;

const cmdParts = [
  `mkdir -p /home/node/output`,
  `wget -q --timeout=300 -O "${heygenPath}" "${heygenVideoUrl.replace(/"/g, '\\"')}"`,
  `wget -q --timeout=300 -O "${productPath}" "${productVideoUrl.replace(/"/g, '\\"')}"`,
  `ffmpeg -y -i "${heygenPath}" -stream_loop -1 -i "${productPath}"${musicInput} -filter_complex '${filterComplex}' -map '[vout]' -map '${audioFinal}' -c:v libx264 -preset fast -crf 23 -c:a aac -b:a 128k -shortest "${outputPath}"`,
  `rm -f "${heygenPath}" "${productPath}"`,
  `echo "DONE:${outputPath}"`
];

return [{ json: {
  session_id: sessionId,
  command: cmdParts.join(' && '),
  final_video_url: outputPath,
  heygen_video_url: heygenVideoUrl,
  product_video_url: productVideoUrl
}}];

